from fractions import Fraction

def calculate_transition_matrix(n):
    transition_matrix = [[0.0 for _ in range(n)] for _ in range(n)]
    for i in range(n):
        if i == 0:
            transition_matrix[i][i] = 0.5
            transition_matrix[i][i + 1] = 0.5
        elif i == n - 1:
            transition_matrix[i][i - 1] = 0.5
            transition_matrix[i][i] = 0.5
        else:
            transition_matrix[i][i - 1] = 0.5
            transition_matrix[i][i + 1] = 0.5
    return transition_matrix

def matrix_multiply(a, b):
    n = len(a)
    result = [[0.0 for _ in range(n)] for _ in range(n)]
    for i in range(n):
        for j in range(n):
            for k in range(n):
                result[i][j] += a[i][k] * b[k][j]
    return result

def matrix_vector_multiply(matrix, vector):
    n = len(matrix)
    result = [0.0 for _ in range(n)]
    for i in range(n):
        for j in range(n):
            result[i] += matrix[i][j] * vector[j]
    return result

def calculate_probability(n, x, y, d):
    transition_matrix = calculate_transition_matrix(n)
    probability_not_meet = 1.0
    bear1_position = [0.0 for _ in range(n)]
    bear1_position[x - 1] = 1.0
    bear2_position = [0.0 for _ in range(n)]
    bear2_position[y - 1] = 1.0
    for _ in range(d):
        bear1_position = matrix_vector_multiply(transition_matrix, bear1_position)
        bear2_position = matrix_vector_multiply(transition_matrix, bear2_position)
        probability_not_meet_day = 1.0
        for i in range(n):
            probability_not_meet_day -= bear1_position[i] * bear2_position[i]
        probability_not_meet *= probability_not_meet_day
    probability_meet = 1.0 - probability_not_meet
    return Fraction(probability_meet).limit_denominator()

def main():
    n, x, y, d = map(int, input().split())
    probability = calculate_probability(n, x, y, d)
    print(f"{probability.numerator}/{probability.denominator}")

if __name__ == "__main__":
    main()
