from fractions import Fraction

def calculate_transition_matrix(n):
    transition_matrix = [[0.0 for _ in range(n)] for _ in range(n)]
    for i in range(n):
        if i == 0:
            transition_matrix[i][0] = 0.5
            transition_matrix[i][1] = 0.5
        elif i == n - 1:
            transition_matrix[i][n - 1] = 0.5
            transition_matrix[i][n - 2] = 0.5
        else:
            transition_matrix[i][i - 1] = 0.5
            transition_matrix[i][i + 1] = 0.5
    return transition_matrix

def matrix_multiply(a, b):
    n = len(a)
    result = [[0.0 for _ in range(n)] for _ in range(n)]
    for i in range(n):
        for j in range(n):
            for k in range(n):
                result[i][j] += a[i][k] * b[k][j]
    return result

def matrix_power(matrix, n):
    if n == 1:
        return matrix
    if n % 2 == 0:
        half_pow = matrix_power(matrix, n // 2)
        return matrix_multiply(half_pow, half_pow)
    else:
        half_pow = matrix_power(matrix, n // 2)
        return matrix_multiply(matrix_multiply(half_pow, half_pow), matrix)

def calculate_probability(n, x, y, d):
    transition_matrix = calculate_transition_matrix(n)
    initial_distribution = [0.0] * n
    initial_distribution[x - 1] = 1.0
    initial_distribution[y - 1] = 1.0
    prob_forage_together = 0.0
    for day in range(1, d + 1):
        distribution_x = matrix_multiply([initial_distribution[:n]], matrix_power(transition_matrix, day))[0]
        distribution_y = matrix_multiply([initial_distribution[n:]], matrix_power(transition_matrix, day))[0]
        prob_forage_together_day = sum(a * b for a, b in zip(distribution_x, distribution_y))
        prob_forage_together = 1 - (1 - prob_forage_together) * (1 - prob_forage_together_day)
    return prob_forage_together

def main():
    n, x, y, d = map(int, input().split())
    initial_distribution = [0.0] * (2 * n)
    initial_distribution[x - 1] = 1.0
    initial_distribution[n + y - 1] = 1.0
    prob_forage_together = 1 - (1 - calculate_probability(n, x, y, d))
    fraction = Fraction(prob_forage_together).limit_denominator()
    print(f'{fraction.numerator}/{fraction.denominator}')

if __name__ == "__main__":
