    # Clean the plaintext
    cleaned_text = ''.join(filter(str.isalpha, plaintext)).lower()
    n = len(cleaned_text)

    # Convert key to sequence of numbers
    key_sequence = [ord(c) - ord('a') + 2 for c in key]

    # Initialize ciphertext
    ciphertext = ['_'] * n

    # Initialize variables
    idx = 0
    direction = 1
    key_idx = 0

    while idx < n:
        step = key_sequence[key_idx % len(key_sequence)]
        if direction == 1:
            pos = 0
            while pos < n and idx < n:
                if ciphertext[pos] == '_':
                    if (pos + 1) % step == 0:
                        ciphertext[pos] = cleaned_text[idx]
                        idx += 1
                pos += 1
        else:
            pos = n - 1
            while pos >= 0 and idx < n:
                if ciphertext[pos] == '_':
                    if (n - pos) % step == 0:
                        ciphertext[pos] = cleaned_text[idx]
                        idx += 1
                pos -= 1
        direction *= -1
        key_idx += 1

    return ''.join(ciphertext)


