def egcd(a, b):
    if a == 0:
        return b, 0, 1
    else:
        gcd, x, y = egcd(b % a, a)
        return gcd, y - (b // a) * x, x

def modinv(a, m):
    gcd, x, y = egcd(a, m)
    if gcd != 1:
        return None
    else:
        return x % m

def chinese_remainder(n, a):
    sum = 0
    prod = 1

    for n_i in n:
        prod *= n_i

    for n_i, a_i in zip(n, a):
        p = prod // n_i
        sum += a_i * modinv(p, n_i) * p
    return sum % prod

def main():
    n = int(input())
    s = input().strip()
    moduli = list(range(n, 1, -1))
    remainders = []
    alphabet = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'
    index_map = {alphabet[i]: i for i in range(n)}
    for i, c in enumerate(s):
        remainders.append((index_map[c] - i) % (n - i))
    try:
        m = chinese_remainder(moduli, remainders)
        print('YES')
        print(m)
    except:
        print('NO')

if __name__ == "__main__":
    main()
