    western_emoticons = [r':\)', r':-\)', r':-\(', r';-\)', r'xD']
    eastern_emoticons = [r'\^\_\^', r'-_-', r'\^o\^', r'\^\^;', r'\(\.\.\)']
    count = 0
    i = 0
    while i < len(s):
        for emoticon in western_emoticons:
            if re.match(emoticon, s[i:]):
                count += 1
                i += len(emoticon) - 1
                break
        else:
            for emoticon in eastern_emoticons:
                if re.match(emoticon, s[i:]):
                    count += 1
                    i += len(emoticon) - 1
                    break
            else:
                i += 1
    return count

def main():
    s = sys.stdin.readline().strip()
    chars = set(s)
    min_length = float('inf')
    max_length = float('-inf')
    for char1 in chars:
        for char2 in chars:
            new_s = s.replace(char1, char2)
            emoticon_count = count_emoticons(new_s)
            length = len(new_s) - emoticon_count
            min_length = min(min_length, length)
            max_length = max(max_length, length)
    print(min_length, max_length)

if __name__ == '__main__':
    main()
