import sys

def read_input():
    return sys.stdin.readline().strip()

def parse_input():
    n, t = read_input().split()
    n = int(n)
    root_type = t == 'A'
    levels = []
    for _ in range(n):
        level = read_input().split()
        levels.append(level)
    return n, root_type, levels

def build_tree(levels, root_type):
    node_count = int(levels[0][0])
    level = []
    for i in range(node_count):
        level.append({'type': root_type, 'children': [], 'value': None})
    nodes = [level]
    for i, l in enumerate(levels[1:]):
        node_type = not root_type if (i + 1) % 2 == 0 else root_type
        index = 0
        level = []
        for node in nodes[-1]:
            for _ in range(int(node['children'][0]) if node['children'] else 1):
                if l[index] == 'T':
                    level.append({'type': None, 'value': True})
                elif l[index] == 'F':
                    level.append({'type': None, 'value': False})
                else:
                    child_count = int(l[index])
                    level.append({'type': node_type, 'children': [child_count], 'value': None})
                index += 1
            node['children'] = node['children'][1:]
        nodes.append(level)
    return nodes

def evaluate_node(node):
    if node['value'] is not None:
        return node['value'], 0, 1
    children_values = [evaluate_node(child) for child in node['children']]
    if node['type']:
        value = all([v for v, _, _ in children_values])
        changes_to_flip = min([c for _, c, _ in children_values]) if value else sum([c for _, c, _ in children_values])
        leaf_count = sum([lc for _, _, lc in children_values])
        return value, changes_to_flip, leaf_count
    else:
        value = any([v for v, _, _ in children_values])
        changes_to_flip = sum([c for _, c, _ in children_values]) if value else min([c for _, c, _ in children_values])
        leaf_count = sum([lc for _, _, lc in children_values])
        return value, changes_to_flip, leaf_count

def main():
    n, root_type, levels = parse_input()
    nodes = build_tree(levels, root_type)
    root = {'type': root_type, 'children': nodes[1], 'value': None}
    for i, node in enumerate(nodes[0]):
        node['children'] = [nodes[1][i]]
    value, changes_to_flip, _ = evaluate_node(root)
    print(changes_to_flip)

if __name__ == "__main__":
    main()
