def parse_location(loc):
    row = ord(loc[0]) - ord('A')
    col = int(loc[1]) - 1
    return row, col

def unparse_location(row, col):
    return chr(ord('A') + row) + str(col + 1)

def is_valid_move(board, piece, loc1, loc2):
    row1, col1 = parse_location(loc1)
    row2, col2 = parse_location(loc2)
    if board[row2][col2] == '.':
        return False
    if piece == 'N':
        dr = abs(row2 - row1)
        dc = abs(col2 - col1)
        return (dr == 2 and dc == 1) or (dr == 1 and dc == 2)
    elif piece == 'B':
        dr = row2 - row1
        dc = col2 - col1
        return dr == dc or dr == -dc
    elif piece == 'R':
        return row1 == row2 or col1 == col2
    elif piece == 'Q':
        dr = row2 - row1
        dc = col2 - col1
        return dr == dc or dr == -dc or row1 == row2 or col1 == col2
    elif piece == 'K':
        dr = abs(row2 - row1)
        dc = abs(col2 - col1)
        return dr <= 1 and dc <= 1
    return False

def get_valid_moves(board, pieces, piece, loc):
    valid_moves = []
    row, col = parse_location(loc)
    for i in range(len(board)):
        for j in range(len(board[0])):
            new_loc = unparse_location(i, j)
            if is_valid_move(board, piece, loc, new_loc) and board[i][j] != '.':
                valid_moves.append(new_loc)
    return valid_moves

def backtrack(board, pieces, moves, num_pieces):
    if len(pieces) == 1:
        return moves
    min_moves = None
    for i, (piece, loc) in enumerate(pieces):
        valid_moves = get_valid_moves(board, pieces, piece, loc)
        for new_loc in valid_moves:
            new_board = [row[:] for row in board]
            new_pieces = pieces[:]
            row1, col1 = parse_location(loc)
            row2, col2 = parse_location(new_loc)
            new_board[row1][col1] = '.'
            new_board[row2][col2] = piece
            new_pieces.remove((piece, loc))
            new_pieces.remove((new_board[row2][col2], new_loc))
            new_pieces.append((piece, new_loc))
            new_moves = moves + [(piece, loc, new_loc)]
            new_num_pieces = num_pieces - 1
            result = backtrack(new_board, new_pieces, new_moves, new_num_pieces)
            if result is not None:
                if min_moves is None or result < min_moves:
                    min_moves = result
    return min_moves

def main():
    import sys
    n, m = map(int, sys.stdin.readline().strip().split())
    board = [['.' for _ in range(n)] for _ in range(n)]
    pieces = []
    for _ in range(m):
        piece, loc = sys.stdin.readline().strip().split()
        row, col = parse_location(loc)
        board[row][col] = piece
        pieces.append((piece, loc))
    result = backtrack(board, pieces, [], m)
    if result is None:
        print('No solution')
    else:
        for piece, loc1, loc2 in result:
            print(f'{piece}: {loc1} -> {loc2}')

if __name__ == '__main__':
    main()
