from collections import deque

def min_cost_flow(graph, source, sink):
    n = len(graph)
    level = [0] * n
    iter = [0] * n

    def bfs(s):
        nonlocal level
        level = [0] * n
        level[s] = 1
        queue = deque([s])
        while queue:
            v = queue.popleft()
            for w, cap, _ in graph[v]:
                if cap > 0 and level[w] == 0:
                    level[w] = level[v] + 1
                    queue.append(w)

    def dfs(v, t, f):
        if v == t:
            return f
        for i in range(iter[v], len(graph[v])):
            iter[v] = i
            w, cap, rev = edge = graph[v][i]
            if cap > 0 and level[v] < level[w]:
                d = dfs(w, t, min(f, cap))
                if d > 0:
                    edge[1] -= d
                    graph[w][rev][1] += d
                    return d
        return 0

    total_flow = 0
    while True:
        bfs(source)
        if level[sink] == 0:
            return total_flow
        iter = [0] * n
        while True:
            flow = dfs(source, sink, float('inf'))
            if flow > 0:
                total_flow += flow
            else:
                break

def main():
    n, m = map(int, input().split())
    graph = [[] for _ in range(n + 2)]
    source = n
    sink = n + 1

    for _ in range(m):
        u, v = map(int, input().split())
        u -= 1
        v -= 1
        graph[u].append([v, float('inf'), len(graph[v])])
        graph[v].append([u, 0, len(graph[u]) - 1])
        graph[v].append([u, float('inf'), len(graph[u])])
        graph[u].append([v, 0, len(graph[v]) - 1])

    prev_teams = input().strip()
    for i, team in enumerate(prev_teams):
        if team == '1':
            graph[source].append([i, 1, len(graph[i])])
            graph[i].append([source, 0, len(graph[source]) - 1])
        else:
            graph[i].append([sink, 1, len(graph[sink])])
            graph[sink].append([i, 0, len(graph[i]) - 1])
        graph[i].append([sink, 2, len(graph[sink])])
        graph[sink].append([i, 0, len(graph[i]) - 1])

    min_cost = min_cost_flow(graph, source, sink)
    print(min_cost)

if __name__ == "__main__":
