from collections import deque

def bfs(graph, source, sink, parent):
    visited = [False] * len(graph)
    queue = deque()
    queue.append(source)
    visited[source] = True
    while queue:
        u = queue.popleft()
        for ind, val in enumerate(graph[u]):
            if visited[ind] == False and val > 0:
                queue.append(ind)
                visited[ind] = True
                parent[ind] = u
                if ind == sink:
                    return True
    return False

def ford_fulkerson(graph, source, sink):
    parent = [-1] * len(graph)
    max_flow = 0
    while bfs(graph, source, sink, parent):
        path_flow = float("Inf")
        s = sink
        while(s != source):
            path_flow = min(path_flow, graph[parent[s]][s])
            s = parent[s]
        max_flow += path_flow
        v = sink
        while(v != source):
            u = parent[v]
            graph[u][v] -= path_flow
            graph[v][u] += path_flow
            v = parent[v]
    return max_flow

def main():
    n, m = map(int, input().split())
    graph = [[0] * (n + 2) for _ in range(n + 2)]
    for _ in range(m):
        u, v = map(int, input().split())
        u -= 1
        v -= 1
        graph[u][v] = 1
        graph[v][u] = 1
    s = input().strip()
    for i in range(n):
        if s[i] == '1':
            graph[0][i + 1] = float('inf')
        else:
            graph[i + 1][-1] = float('inf')
    min_cost = ford_fulkerson(graph, 0, n + 1)
    cost = 0
    for i in range(n):
        if graph[0][i + 1] == float('inf'):
            cost += 1
        elif graph[i + 1][-1] == float('inf'):
            cost += 0
        else:
            cost += 2
    print(min(min_cost, cost))

if __name__ == "__main__":
    main()
