    n = int(input().strip())
    min_sum = 0
    max_sum = 0
    for _ in range(n):
        hex_str = input().strip().upper()
        min_hex, max_hex = get_min_max_hex(hex_str)
        if hex_str[0] in ['0', '8', 'B', 'D']:
            min_val = hex_to_dec(min_hex) if min_hex != '0' else float('inf')
