import sys
from collections import defaultdict
import bisect

def main():
    input = sys.stdin.readline
    N, M = map(int, input().split())

    spies = {}
    x_coords = defaultdict(list)
    y_coords = defaultdict(list)

    for i in range(1, N + 1):
        x, y = map(int, input().split())
        spies[i] = (x, y)
        x_coords[x].append((y, i))
        y_coords[y].append((x, i))

    for coord_list in x_coords.values():
        coord_list.sort(key=lambda x: x[0])
    for coord_list in y_coords.values():
        coord_list.sort(key=lambda x: x[0])

    eliminated = set()

    for _ in range(M):
        team, direction = input().split()
        team = int(team)

        if team in eliminated:
            print('ignore')
            continue

        x, y = spies[team]
        eliminated_spies = []

        if direction == 'N':
            idx = bisect.bisect_left([yy for yy, _ in x_coords[x]], y)
            for y_coord, spy in x_coords[x][idx:]:
                if y_coord > y:
                    eliminated_spies.append(spy)
                    eliminated.add(spy)
            x_coords[x] = [item for item in x_coords[x] if item[0] <= y]

        elif direction == 'S':
            idx = bisect.bisect_right([yy for yy, _ in x_coords[x]], y)
            for y_coord, spy in x_coords[x][:idx]:
                if y_coord < y:
                    eliminated_spies.append(spy)
                    eliminated.add(spy)
            x_coords[x] = [item for item in x_coords[x] if item[0] >= y]

        elif direction == 'E':
            idx = bisect.bisect_left([xx for xx, _ in y_coords[y]], x)
            for x_coord, spy in y_coords[y][idx:]:
                if x_coord > x:
                    eliminated_spies.append(spy)
                    eliminated.add(spy)
            y_coords[y] = [item for item in y_coords[y] if item[0] <= x]

        elif direction == 'W':
            idx = bisect.bisect_right([xx for xx, _ in y_coords[y]], x)
            for x_coord, spy in y_coords[y][:idx]:
                if x_coord < x:
                    eliminated_spies.append(spy)
                    eliminated.add(spy)
            y_coords[y] = [item for item in y_coords[y] if item[0] >= x]

        if team in eliminated_spies:
            eliminated_spies.remove(team)

        print(len(eliminated_spies), *eliminated_spies)

